<?php

declare(strict_types=1);

namespace App\AlgebraicAlgorithms;

/*
 * Для запуска в консоли из папки с файлом набрать php NumberInPow.php
 */
class FibonnaciNumbers
{
    public static function getFibonacciIterative(int $number): int|string
    {
        if ($number <= 2) {
            return 1;
        }

        $first = '1';
        $second = '1';

        if ($number >= 150) {
            $result = self::getFibonacciMatrix([['1', '1'], ['1', '0']], $number);
            return $result[0][1];
        }

        $result = 0;
        for ($i = 3; $i <= $number; ++$i) {
            $result = bcadd($first, $second);
            $first = $second;
            $second = $result;
        }

        return $result;
    }

    private static function useBine(int $number): string
    {
        $fi = (1.0 + sqrt(5)) / 2.0;
        $value = bcdiv((bcpow((string) $fi, (string) $number)), bcsqrt('5'));

        return bcfloor(bcadd($value, bcdiv('1.0','2.0')));
    }

    /**
     * Функция производит умножений двух матриц размерностью 2х2
     *
     * @param array $a
     * @param array $b
     * @return array
     */
    public static function multiplyMatrix(array $a, array $b): array
    {
        $result = array_fill(0, 2, array_fill(0, 2, 0));

        for ($i = 0; $i < 2; $i++) {
            for ($j = 0; $j < 2; $j++) {
                // Работаем с 2х2
                $value = '0';
                for ($k = 0; $k < 2; $k++) {
                    $value = bcadd($value, bcmul($a[$i][$k], $b[$k][$j]));
                }

                $result[$i][$j] = $value;
            }
        }

        return $result;
    }

    public static function getFibonacciMatrix(array $a, int $number): array
    {
        if ($number <= 1) {
            return $a;
        }

        $b = self::getFibonacciMatrix($a, (int) ($number / 2));
        if ($number & 1) {
            $b = self::multiplyMatrix($b, $b);
            return self::multiplyMatrix($a, $b);
        }

        return self::multiplyMatrix($b, $b);
    }
}

